class Piece:
    def __init__(self, color):
        self.color = color
        self.king = False

    def make_king(self):
        self.king = True


class Board:
    def __init__(self):
        self.board = []
        self.setup_board()

    def setup_board(self):
        for row in range(8):
            if row % 2 == 0:
                self.board.append([Piece('white') if (col + row) % 2 != 0 else None for col in range(8)])
            else:
                self.board.append([Piece('red') if (col + row) % 2 != 0 else None for col in range(8)])

    def display_board(self):
        for row in self.board:
            print(" ".join(['{}' if piece is not None else '--' for piece in row]))
        print()


class Player:
    def __init__(self, color):
        self.color = color
        self.captured_pieces = 0


class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.players = {'red': Player('red'), 'white': Player('white')}
        self.current_player = 'red'

    def switch_turn(self):
        self.current_player = 'white' if self.current_player == 'red' else 'red'

    def display_game_state(self):
        print(f"Current Player: {self.current_player}")
        self.board.display_board()

    def run(self):
        while True:
            self.display_game_state()
